<section class="container section narrow-wide"><div class="panel"><h1>Nueva reservación</h1><form method="post" action="index.php?route=reservation/store" id="reservationForm"><input type="hidden" name="csrf_token" value="<?=Security::csrfToken()?>"><label>Hotel<select name="hotel_id" required><option value="">Seleccione</option><?php foreach($hotels as $h):?><option value="<?=$h['id']?>"><?=Security::e($h['name'])?> - ₡<?=number_format($h['price_per_night'])?></option><?php endforeach;?></select></label><div class="form-grid"><label>Entrada<input type="date" name="check_in" required></label><label>Salida<input type="date" name="check_out" required></label></div><label>Personas<input type="number" name="people" min="1" max="20" value="1" required></label><fieldset><legend>Actividades opcionales</legend><?php foreach($activities as $a):?><label class="check"><input type="checkbox" name="activities[]" value="<?=$a['id']?>"> <?=Security::e($a['name'])?> — ₡<?=number_format($a['price'])?> por persona</label><?php endforeach;?></fieldset><label>Notas<textarea name="notes" maxlength="500"></textarea></label><button class="btn">Confirmar reservación</button></form></div></section>
